import{_ as t,o as i,c as l,a2 as e}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"F17: 籌碼分佈與法人動態分析 - 投資研究員 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/8064_東捷/20260429/F17_籌碼分佈與法人動態分析_投資研究員.md","filePath":"審計報告庫/財務審計/8064_東捷/20260429/F17_籌碼分佈與法人動態分析_投資研究員.md"}'),r={name:"審計報告庫/財務審計/8064_東捷/20260429/F17_籌碼分佈與法人動態分析_投資研究員.md"};function o(n,a,s,h,c,_){return i(),l("div",null,[...a[0]||(a[0]=[e('<h1 id="f17-籌碼分佈與法人動態分析-投資研究員-審計報告" tabindex="-1">F17: 籌碼分佈與法人動態分析 - 投資研究員 審計報告 <a class="header-anchor" href="#f17-籌碼分佈與法人動態分析-投資研究員-審計報告" aria-label="Permalink to &quot;F17: 籌碼分佈與法人動態分析 - 投資研究員 審計報告&quot;">​</a></h1><p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的財務洞見。</p><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>外資、投信與自營商的近期買賣超動向為何？千張大戶持股比例是否發生結構性變化？</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li><strong>核心結論</strong>：外資主導高頻換手(單日±5,000張以上)，投信零參與排除鎖碼特徵。千張大戶一週回補920bps(35.28%→44.48%)，籌碼波動中重新集中。</li><li><strong>風險評級</strong>：中</li><li><strong>數據時效</strong>：根據截至2026年4月29日最新公開數據</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><ul><li><strong>重點數據</strong>：外資4月淨賣超6,379張；投信買賣超=0張；自營商合計+226張；千張大戶：42.98%→45.23%→35.28%→44.48%；籌碼集中度4/24=52.25%；股東總數60,308→65,438人(+8.5%)。</li><li><strong>診斷見解</strong>：投信零參與排除鎖碼可能；外資單日進出達發行量3~4%，屬短線量化資金；千張一週+920bps顯示大戶積極吸籌，非結構鬆動。判定為「主力高週轉換手，股東人數上升須警惕」。</li></ul><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="子議題一-三大法人買賣超動向-4週逐日追蹤" tabindex="-1">子議題一：三大法人買賣超動向 (4週逐日追蹤) <a class="header-anchor" href="#子議題一-三大法人買賣超動向-4週逐日追蹤" aria-label="Permalink to &quot;子議題一：三大法人買賣超動向 (4週逐日追蹤)&quot;">​</a></h3><ul><li><strong>核心重點</strong>：外資4月(4/1~4/29)淨賣超總計約-6,379張，佔發行量3.86%。投信整月買賣超歸零。自營商4月下旬合計+226張(自行+避險合計)。 <ul><li>關鍵轉折日：4/14外資單日-7,526張(最大淨賣出)；4/24外資+5,359張(最大淨買入)；4/27外資-5,811張；4/28~29外資+4,831/+3,100張</li><li>三大法人合計未有單日同步買超或賣超超過千張的共識行為</li></ul></li><li><strong>深度見解</strong>：外資買賣超標準差極大(±3,800張/日)，遠高於一般中小型股的±300~500張，暗示參與者為短線程式交易或套利資金。投信零參與意味東捷不在投信核心持股名單，排除法人鎖碼特徵。自營商微量參與表明該股非權證發行或避險主力標的。</li></ul><h3 id="子議題二-千張大戶持股結構性變化" tabindex="-1">子議題二：千張大戶持股結構性變化 <a class="header-anchor" href="#子議題二-千張大戶持股結構性變化" aria-label="Permalink to &quot;子議題二：千張大戶持股結構性變化&quot;">​</a></h3><ul><li><strong>核心重點</strong>：千張大戶持股比例近4週波動劇烈：4/2=42.98%→4/10=45.23%(+225bps)→4/17=35.28%(-995bps)→4/24=44.48%(+920bps)。最新絕對值44.48%係由25人持有82,225張。 <ul><li>股權分散表(4/24)：&lt;10張散戶共64,161人/23.4%持股；總股東65,438人</li><li>對比3/20總股東60,308人，4週內+5,130人(+8.5%)</li><li>從2025年11月千張大戶約30%的低基期算起，目前44.48%屬12個月區間上緣(最高點為4/10的45.23%)</li></ul></li><li><strong>深度見解</strong>：4/17千張大戶驟降至35.28%的異常事件，與同日外資僅+1,364張不匹配，推測為大戶間的大額次級市場轉讓或特定股東申報減碼。一週後回補至44.48%顯示接盤方強勢。散戶人數增長8.5%但千張大戶比例未降(反而從35.28%回升)，排除經典派發結構(股價漲+散戶增+大戶減)。屬「漲勢中散戶追入但仍被大戶接走籌碼」的中性偏多格局。</li></ul><h2 id="💡-專家評析-skepticism-mandate" tabindex="-1">💡 專家評析 (Skepticism Mandate) <a class="header-anchor" href="#💡-專家評析-skepticism-mandate" aria-label="Permalink to &quot;💡 專家評析 (Skepticism Mandate)&quot;">​</a></h2><ul><li><strong>空頭風險一—外資短線撤離與波動陷阱</strong>：4月外資累計仍淨賣超6,379張，近期買回可能只是短線回補。若外資結束波段操作轉為趨勢性撤退，散戶人數已增8.5%形成的賣壓將被放大。94.9元股價從36.8元低點已+158%，籌碼成本極度不均。</li><li><strong>空頭風險二—投信結帳壓力不存在但私募鎖倉解套風險</strong>：志聖3/20以10.17億認購私募(持股10.82%，成本估低於市價甚多)。私募股通常有3年閉鎖期，短期不構成賣壓。但董監持股從18.88%降至16.84%(稀釋效果)，且志聖取得席次後是否有經營權策略變數，屬非籌碼面黑天鵝。</li><li><strong>無投信結帳壓力</strong>：投信持股為零，排除投信季底拚績效或結帳風險。但相對地也意味缺乏法人認同的穩定買盤錨。</li></ul><h2 id="📚-證據來源-veracity-check" tabindex="-1">📚 證據來源 (Veracity Check) <a class="header-anchor" href="#📚-證據來源-veracity-check" aria-label="Permalink to &quot;📚 證據來源 (Veracity Check)&quot;">​</a></h2><ul><li><strong>Web Search (HiStock 籌碼集中度歷史資料)</strong>：OK — 2026/04/24~2025/08/01共35期週資料完整取得，含籌碼集中度、外資籌碼、大戶籌碼、董監持股</li><li><strong>Web Search (法人力買賣超逐日資料)</strong>：OK — 取得2026/4/1~4/29共18個交易日之外資、投信、自營商買賣超（來源: Goodinfo/HiStock）</li><li><strong>Web Search (股權分散表)</strong>：OK — 取得2026/4/24各持股分級之人數、張數、佔比（來源: Wantgoo/玩股網）</li><li><strong>關鍵核對碼</strong>：HiStock 籌碼集中度4/24=52.25%/外資13.24%/大戶39.01%；Wantgoo千張大戶4/24=44.48%(25人/82,225張)；4/29收盤94.9元(+9.97%/漲停/15,538張)</li></ul>',17)])])}const g=t(r,[["render",o]]);export{u as __pageData,g as default};
